arguments.new_str:
var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddSingleton<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
builder.Services.AddHttpClient("api")
    // [Breaking Change 2 & 3] ConfigureHttpMessageHandlerBuilder is obsolete (CS0618)
    // and the default primary handler is now SocketsHttpHandler, not HttpClientHandler,
    // so the old cast would throw InvalidCastException at runtime.
    .UseSocketsHttpHandler((handler, _) =>
    {
        handler.UseCookies = false;
    })
    // [Breaking Change 4] .NET 9 redacts ALL header values in Trace-level
    // HttpClient logs by default. Opt out so headers remain visible for debugging.
    .RedactLoggedHeaders(_ => false);
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

